#include <bits/stdc++.h>
using namespace std;

const int N=1e6+10;

int n,a[N],root,f[N][2],ans,stk[N],top,h[N];
bool b[N],ins[N];
vector<int> g[N];

void dfs1(int x){
	b[x]=1;
    f[x][1]=-1e9;
    for(int y:g[x])
        if((x==root || y!=a[x]) && y!=root){
            dfs1(y);
            f[x][1]=max(f[x][1]+max(f[y][0],f[y][1]),f[x][0]+f[y][0]+1);
            f[x][0]+=max(f[y][0],f[y][1]);
        }
}

void dfs2(int x){
    f[x][1]=(x==a[root]?1:-1e9),f[x][0]=0;
    for(int y:g[x])
        if((x==root || y!=a[x]) && y!=root){
            dfs2(y);
            f[x][1]=max(f[x][1]+max(f[y][0],f[y][1]),f[x][0]+f[y][0]+1);
            f[x][0]+=max(f[y][0],f[y][1]);
        }
}

int ringdfs(int x){
	h[x]=1;
	stk[++top]=x,ins[x]=1;
	if(ins[a[x]]){
		h[x]=2;
		ins[x]=0;
		top--;
		return a[x];
	}
	if(!h[a[x]]){
		int tmp=ringdfs(a[x]);
		ins[x]=0;
		top--;
		if(tmp!=a[x]){
			h[x]=2;
			return tmp;
		}
		return x;
	}
	ins[x]=0;
	top--;
	return x;
}

int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++){
        scanf("%d",&a[i]);
        g[a[i]].push_back(i);
    }
    for(int i=1;i<=n;i++)
    	if(!h[i])
    		ringdfs(i);
    for(int i=1;i<=n;i++)
        if(!b[i] && h[i]==2){
            root=i;
            dfs1(root);
            int tmp=max(f[root][0],f[root][1]);
            dfs2(root);
            ans+=max(tmp,f[root][0]);
        }
    printf("%d",ans);
    return 0;
}
